import { Component, OnInit } from '@angular/core';
import { Achievement } from '../../shared/models';
import { PortfolioService } from '../../core/services/portfolio.service';

@Component({
  selector: 'app-achievements',
  templateUrl: './achievements.component.html',
  styleUrls: ['./achievements.component.scss']
})
export class AchievementsComponent implements OnInit {
  achievements: Achievement[] = [];

  constructor(private portfolioService: PortfolioService) {}

  ngOnInit(): void {
    this.portfolioService.getAchievements().subscribe(a => this.achievements = a);
  }
}
<section class="section">
  <div class="container">
    <span class="term-label">grep -r "won\|hosted\|shadowed" .</span>
    <h1>Achievements</h1>

    <div class="achievements__list">
      <div class="card achievement" *ngFor="let a of achievements">
        <div class="achievement__header">
          <h3>{{ a.title }}</h3>
          <span class="tag">{{ a.category }}</span>
        </div>
        <p>{{ a.description }}</p>
        <p class="achievement__date" *ngIf="a.dateLabel">{{ a.dateLabel }}</p>
      </div>
    </div>
  </div>
</section>
